function createAggregateError(errors) {
  const Agg = (typeof globalThis !== 'undefined' && globalThis.AggregateError) ? globalThis.AggregateError : null;
  if (typeof Agg === 'function') {
    return new Agg(errors, 'All promises were rejected');
  }
  const err = new Error('All promises were rejected');
  try { err.name = 'AggregateError'; } catch { try { Object.defineProperty(err, 'name', { value: 'AggregateError' }); } catch {} }
  err.errors = errors;
  return err;
}


export default function promiseAny(promises) {
  if (!Array.isArray(promises)) {
    return Promise.reject(new TypeError('Argument must be an array'));
  }
  const n = promises.length;
  if (n === 0) {
    return Promise.reject(createAggregateError([]));
  }

  return new Promise((resolve, reject) => {
    const errors = new Array(n);
    let rejected = 0;

    promises.forEach((p, i) => {
      Promise.resolve(p).then(
        (value) => resolve(value),
        (err) => {
          errors[i] = err;
          rejected += 1;
          if (rejected === n) {
            reject(createAggregateError(errors));
          }
        }
      );
    });
  });
}
